parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "nombre": {
      "type": "string",
      "description": "Nombre completo del lead (padre o estudiante)"
    },
    "email": {
      "type": "string",
      "description": "Correo electrónico de contacto"
    },
    "telefono": {
      "type": "string",
      "description": "Número de teléfono o WhatsApp de contacto"
    },
    "materia": {
      "type": "string",
      "description": "Materia o curso que necesita reforzar"
    },
    "nivel": {
      "type": "string",
      "description": "Nivel académico del estudiante (Primaria, Secundaria, Bachillerato, Universidad)"
    },
    "descripcion": {
      "type": "string",
      "description": "Descripción breve del problema o urgencia"
    }
  },
  "required": ["nombre", "email", "telefono", "materia"]
}
